    keywords: ['transparencia activa', 'publicación proactiva', 'web', 'salarios', 'contratos', 'licitaciones', 'declaraciones juradas'],
    order: 32,
    segments: [{ id: 'seg-27275-32-0', lawId: 'ley-27275', articleId: 'art-27275-32', articleNumber: '32', segmentType: 'PARAGRAPH', originalText: 'Transparencia activa: publicar proactivamente en web estructura, salarios, contratos, presupuesto, auditorías, resoluciones.', plainExplanation: 'La información que debe estar en la web no necesita ser pedida: ya debe estar disponible. Si no está, es un incumplimiento.', practicalExample: 'Los sueldos de los funcionarios públicos deben publicarse en la web del organismo sin que nadie los pida.', references: [], order: 0 }],
